import pytest
from rest_framework.test import APIClient

@pytest.fixture
def api_client() -> APIClient:
    return APIClient()

@pytest.fixture
def authed_client(user) -> APIClient:
    client = APIClient()
    client.force_authenticate(user=user)
    return client

@pytest.fixture
def staff_client(user_factory) -> APIClient:
    staff_user = user_factory(is_staff=True)
    client = APIClient()
    client.force_authenticate(user=staff_user)
    return client

@pytest.mark.django_db
def test_create_user(api_client, organization):
    payload = {
        "email": "alice@example.com",
        "password": "SecurePass123!",
        "first_name": "Alice",
    }
    response = api_client.post("/api/v1/users/", payload, format="json")

    assert response.status_code == 201
    assert response.data["email"] == "alice@example.com"
    assert response.data["first_name"] == "Alice"
    assert "password" not in response.data     # Never leak passwords
    assert "id" in response.data               # ID assigned

import pytest

@pytest.mark.django_db
@pytest.mark.parametrize("client_fixture,expected_status", [
    ("api_client", 401),         # Unauthenticated
    ("authed_client", 200),      # Authenticated member
    ("staff_client", 200),       # Staff member
])
def test_order_list_permissions(request, client_fixture, expected_status):
    client = request.getfixturevalue(client_fixture)
    response = client.get("/api/v1/orders/")
    assert response.status_code == expected_status

@pytest.mark.django_db
@pytest.mark.parametrize("client_fixture,expected_status", [
    ("api_client", 401),
    ("authed_client", 403),      # Authed but not owner — forbidden
    ("staff_client", 200),       # Staff can access any order
])
def test_order_detail_permissions(
    request, client_fixture, expected_status, order
):
    client = request.getfixturevalue(client_fixture)
    response = client.get(f"/api/v1/orders/{order.id}/")
    assert response.status_code == expected_status
